// Device Settings
package snmp

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40510/idl"
	"github.com/arminguenther/xeruspower-go/v40510/idl/event"
)

const ERR_INVALID_PARAMS int32 = 1 // Invalid parameters

// SNMP agent settings interface
type Snmp interface {
	idl.Object

	// Retrieve the SNMP agent configuration.
	//
	//	@return SNMP agent configuration
	GetConfiguration(ctx context.Context) (Configuration, error)

	// Set the SNMP agent configuration.
	//
	//	@param cfg  New SNMP agent settings
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	SetConfiguration(ctx context.Context, cfg Configuration) (int32, error)

	// Retrieve the SNMP V3 Engine ID.
	//
	//	@return SNMP V3 Engine ID
	GetV3EngineId(ctx context.Context) (string, error)
}

// SNMP agent configuration
type Configuration struct {
	V2enable    bool   // SNMP v1 / 2c enabled
	V3enable    bool   // SNMP v3 enabled
	ReadComm    string // read community string
	WriteComm   string // write community string
	SysContact  string // system contact
	SysName     string // system name
	SysLocation string // system location
}

type ConfigurationChangedEvent interface {
	event.Event
	UserName() string         // user who triggered event
	IpAddr() string           // ip or device on which user is logged in
	OldConfig() Configuration // old configuration
	NewConfig() Configuration // new configuration
	isConfigurationChangedEvent()
}
